QuestionText:
// 要素への代入
int[] a = {10};
a[0] = 99;
System.out.println(a[0]); // 出力: ____

// 計算利用
int[] a = {2■ 3};
int x = a[0] * a[1];
System.out.println(x); // 出力: ____

// インクリメント
int[] a = {0};
a[0]++;
System.out.println(a[0]); // 出力: ____

// 変数インデックス
int[] a = {10■ 20};
int i = 1;
System.out.println(a[i]); // 出力: ____

// char配列
char[] c = {'A'■ 'B'};
c[1] = 'Z';
System.out.println(c[1]); // 出力: ____

// double配列
double[] d = {1.5};
d[0] += 0.5;
System.out.println(d[0]); // 出力: ____

// コピー代入
int[] a = {5■ 10};
a[0] = a[1];
System.out.println(a[0]); // 出力: ____

// 代入式の値
int[] a = {1};
int x = (a[0] = 5);
System.out.println(x); // 出力: ____

// 演算順序
int[] a = {10};
a[0] = a[0] + 1 * 2;
System.out.println(a[0]); // 出力: ____

// 文字列結合
String[] s = {A};
s[0] = s[0] + B;
System.out.println(s[0]); // 出力: ____

// 論理反転
boolean[] b = {false};
b[0] = !b[0];
System.out.println(b[0]); // 出力: ____

// 上書き
int[] a = {0};
a[0] = 1;
a[0] = 2;
System.out.println(a[0]); // 出力: ____

// 乗算代入
int[] a = {10};
a[0] *= 2;
System.out.println(a[0]); // 出力: ____

// forループ
int[] a = {1■ 2};
for(int i=0; i<____; i++) {
  System.out.print(a[i]);
}

// 拡張for文
int[] a = {10■ 20};
for(int x : a) {
  System.out.print(x);
}
// 出力: ____

// 合計計算
int[] a = {2■ 2■ 2};
int sum = 0;
for(int n : a) sum += n;
System.out.println(sum); // ____

